const express = require('express');
const { ApolloServer, gql } = require('apollo-server-express');
const WebSocket = require('ws');

// Define the GraphQL schema
const typeDefs = gql`
  type ChatMessage {
    id: ID!
    text: String!
    sender: String!
    roomID: String!
  }

  type Query {
    chatMessages(roomID: String!): [ChatMessage]
  }

  type Mutation {
    sendChatMessage(text: String!, sender: String!, roomID: String!): ChatMessage
  }

  type Subscription {
    newChatMessage(roomID: String!): ChatMessage
  }
`;

// In-memory data store for chat messages
let chatMessages = [];

// Resolvers to handle GraphQL operations
const resolvers = {
  Query: {
    chatMessages: (_, { roomID }) => chatMessages.filter(msg => msg.roomID === roomID),
  },
  Mutation: {
    sendChatMessage: (_, { text, sender, roomID }) => {
      const message = { id: Date.now().toString(), text, sender, roomID };
      chatMessages.push(message);
      pubsub.publish('NEW_CHAT_MESSAGE', { newChatMessage: message });
      return message;
    },
  },
  Subscription: {
    newChatMessage: {
      subscribe: (_, { roomID }) => pubsub.asyncIterator(['NEW_CHAT_MESSAGE']),
    },
  },
};

// Create an Apollo Server instance
const server = new ApolloServer({ typeDefs, resolvers });

// Create an Express app
const app = express();

// Apply middleware to the Express app for GraphQL
server.applyMiddleware({ app });

// Set up WebSocket subscriptions
const wss = new WebSocket.Server({ server: app });
const pubsub = new PubSub();
wss.on('connection', (ws, req) => {
  ws.on('message', message => {
    console.log(`Received message => ${message}`);
  });
});

// Start the Express server
app.listen({ port: 4000 }, () =>
  console.log(`🚀 Server ready at http://localhost:4000${server.graphqlPath}`)
);